/**
 * bash 集成脚本模板。
 * 通过 `bind -x` 绑定 Ctrl+G，读取并替换 READLINE_LINE。
 * 需要 bash 4+（`bind -x` + READLINE_LINE/POINT 变量）。
 *
 * 实现细节说明：脚本内容以纯字符串拼接方式构造，避免与 JS 模板插值冲突。
 */
const LINES: string[] = [
  '# >>> WhatTheShell (wts) bash integration >>>',
  '# Generated by: wts shell-init bash',
  '# Install: append the following to ~/.bashrc',
  '#   eval "$(wts shell-init bash)"',
  '',
  '__wts_inline_widget() {',
  '  local current="$READLINE_LINE"',
  '  local intent=""',
  '  local _stty_saved=""',
  '  local _read_rc=0',
  '',
  '  # All user-visible I/O goes through /dev/tty so bind -x\'s readline',
  '  # bookkeeping stays clean. Readline keeps the tty in raw mode, so a',
  '  # bare `read` would not see Enter as line-end — save the tty state,',
  '  # switch to sane (canonical) mode for the prompt, restore immediately',
  '  # after so the outer readline keeps working.',
  '  # We avoid `read -e` deliberately: nesting readline inside a bind -x',
  '  # handler is undefined, and in some terminals (VSCode remote-SSH ->',
  '  # Ubuntu -> docker bash) the user\'s Enter leaked back to the outer',
  '  # readline and auto-executed the command just assigned to READLINE_LINE.',
  '  _stty_saved=$(stty -g </dev/tty 2>/dev/null)',
  '  stty sane </dev/tty 2>/dev/null',
  '',
  '  # Print "wts > " directly on the line readline just wiped — no leading',
  '  # newline, otherwise the wiped prompt row would stay visible as a blank.',
`  IFS= read -r -p $'\x1b[36m[WhatTheShell]\x1b[0m > ' intent </dev/tty`,
  '  _read_rc=$?',
  '',
  '  [[ -n "$_stty_saved" ]] && stty "$_stty_saved" </dev/tty 2>/dev/null',
  '',
  '  if (( _read_rc != 0 )) || [[ -z "$intent" ]]; then',
  '    return 0',
  '  fi',
  '',
  "  printf 'wts: thinking...\\r' >/dev/tty",
  '',
  '  local tmpout tmperr rc',
  '  tmpout=$(mktemp 2>/dev/null) || return 1',
  '  tmperr=$(mktemp 2>/dev/null) || { rm -f "$tmpout"; return 1; }',
  '',
  '  command wts generate --inline --shell bash \\',
  '    --buffer "$current" \\',
  '    --history-file "${HISTFILE:-}" \\',
  '    -- "$intent" \\',
  '    </dev/null >"$tmpout" 2>"$tmperr"',
  '  rc=$?',
  '',
  "  printf '\\r\\033[2K' >/dev/tty",
  '',
  '  if (( rc == 0 )); then',
  '    READLINE_LINE=$(<"$tmpout")',
  '    READLINE_POINT=${#READLINE_LINE}',
  '  else',
  '    cat "$tmperr" >/dev/tty',
  '  fi',
  '',
  '  rm -f "$tmpout" "$tmperr"',
  '}',
  '',
  'bind -x \'"\\C-g":__wts_inline_widget\' 2>/dev/null',
  '# <<< WhatTheShell (wts) bash integration <<<',
  '',
];

export const BASH_INIT_SCRIPT = LINES.join('\n');
